let slide=document.getElementById('slide-content'),audio=document.getElementById('audio-content'),audioUrl=audio.getAttribute('data-audio');function nextslide(){let a=slide.getAttribute('data-slide'),b=parseInt(slide.getAttribute('data-max'));if(a<b){let b=window.location.href+'slide/slide-'+(parseInt(a)+1)+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+(parseInt(a)+1)+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide",parseInt(a)+1)}}function prevslide(){let a=slide.getAttribute('data-slide');if(a>1){let b=window.location.href+'slide/slide-'+(parseInt(a)-1)+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+(parseInt(a)-1)+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide",parseInt(a)-1)}else{let b=window.location.href+'slide/slide-'+a+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+a+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide","1")}}function pauseslide(){audio.pause(),document.getElementById('slide-control').setAttribute("data-icon","pause")}function playslide(){audio.play(),document.getElementById('slide-control').setAttribute("data-icon","play")}function openslide(){document.getElementById('presentation').setAttribute('data-player','play'),screen.width<960&&(document.getElementById('presentation').requestFullscreen(),screen.lockOrientation('landscape')),playslide()}function exitslide(){document.getElementById('presentation').setAttribute('data-player',''),screen.width<960&&(document.getElementById('presentation').exitFullscreen(),screen.lockOrientation('')),audio.pause(),audio.currentTime=0}audio.onended=function(){nextslide()};let act=document.getElementsByClassName('action');for(var i=0;i<act.length;i++)act[i].onclick=function(){switch(this.getAttribute('data-action')){case"play":openslide();break;case"prev":prevslide();break;case"next":nextslide();break;case"pause":pauseslide();break;case"play":playslide(),this.setAttribute("data-action","play");break;case"exit":exitslide()}}